/**
 * Zoom & Pan - Core Module
 * 
 * Pure functions for canvas zoom and pan calculations.
 * Used by useCanvasZoomPan hook and ZoomPanControls component.
 * 
 * Features:
 * - Zoom with configurable limits (MIN_ZOOM to MAX_ZOOM)
 * - Zoom toward mouse cursor position
 * - Fit-to-screen calculation
 * - Pan offset management
 * - Smooth zoom steps
 */

// ============================================================================
// TYPES
// ============================================================================

export interface ZoomPanState {
  /** Current zoom level (1.0 = 100%) */
  zoom: number;
  /** Pan offset X (pixels) */
  panX: number;
  /** Pan offset Y (pixels) */
  panY: number;
}

export interface ZoomPanConfig {
  /** Minimum zoom level */
  minZoom: number;
  /** Maximum zoom level */
  maxZoom: number;
  /** Zoom step for button controls */
  zoomStep: number;
  /** Zoom sensitivity for scroll (smaller = more sensitive) */
  scrollSensitivity: number;
  /** Whether to allow panning beyond canvas bounds */
  allowOverscroll: boolean;
}

export interface ViewportSize {
  width: number;
  height: number;
}

export interface CanvasSize {
  width: number;
  height: number;
}

export interface Point2D {
  x: number;
  y: number;
}

export interface ZoomTowardPointResult {
  zoom: number;
  panX: number;
  panY: number;
}

// ============================================================================
// CONSTANTS
// ============================================================================

/** Minimum zoom: 10% */
export const MIN_ZOOM = 0.1;

/** Maximum zoom: 400% */
export const MAX_ZOOM = 4.0;

/** Default zoom step for buttons */
export const ZOOM_STEP = 0.1;

/** Default scroll sensitivity */
export const SCROLL_SENSITIVITY = 1000;

/** Preset zoom levels for quick selection */
export const ZOOM_PRESETS = [0.1, 0.25, 0.5, 0.75, 1.0, 1.5, 2.0, 3.0, 4.0] as const;

/** Default configuration */
export const DEFAULT_ZOOM_PAN_CONFIG: ZoomPanConfig = {
  minZoom: MIN_ZOOM,
  maxZoom: MAX_ZOOM,
  zoomStep: ZOOM_STEP,
  scrollSensitivity: SCROLL_SENSITIVITY,
  allowOverscroll: false,
};

/** Initial state */
export const INITIAL_ZOOM_PAN_STATE: ZoomPanState = {
  zoom: 1.0,
  panX: 0,
  panY: 0,
};

// ============================================================================
// ZOOM FUNCTIONS
// ============================================================================

/**
 * Clamp zoom level to configured bounds.
 */
export function clampZoom(zoom: number, config: ZoomPanConfig = DEFAULT_ZOOM_PAN_CONFIG): number {
  return Math.min(Math.max(zoom, config.minZoom), config.maxZoom);
}

/**
 * Calculate new zoom level after stepping in/out.
 * Returns clamped zoom value.
 */
export function stepZoom(
  currentZoom: number,
  direction: 'in' | 'out',
  config: ZoomPanConfig = DEFAULT_ZOOM_PAN_CONFIG
): number {
  const delta = direction === 'in' ? config.zoomStep : -config.zoomStep;
  return clampZoom(currentZoom + delta, config);
}

/**
 * Calculate zoom level from scroll wheel delta.
 * Zoom is centered toward the mouse cursor position.
 */
export function calculateScrollZoom(
  currentZoom: number,
  deltaY: number,
  config: ZoomPanConfig = DEFAULT_ZOOM_PAN_CONFIG
): number {
  const zoomFactor = 1 - deltaY / config.scrollSensitivity;
  const newZoom = currentZoom * zoomFactor;
  return clampZoom(newZoom, config);
}

/**
 * Zoom toward a specific point (e.g., mouse cursor position).
 * Adjusts pan offset so the point stays in the same screen position.
 * 
 * @param state - Current zoom/pan state
 * @param newZoom - Target zoom level
 * @param point - Point to zoom toward (in viewport coordinates)
 * @returns New zoom/pan state
 */
export function zoomTowardPoint(
  state: ZoomPanState,
  newZoom: number,
  point: Point2D
): ZoomTowardPointResult {
  const zoomRatio = newZoom / state.zoom;

  // Adjust pan so that the point under cursor stays in the same position
  const newPanX = point.x - (point.x - state.panX) * zoomRatio;
  const newPanY = point.y - (point.y - state.panY) * zoomRatio;

  return {
    zoom: newZoom,
    panX: newPanX,
    panY: newPanY,
  };
}

/**
 * Calculate fit-to-screen zoom level.
 * Finds the zoom that makes the canvas fit entirely within the viewport,
 * with optional padding.
 */
export function calculateFitToScreen(
  canvasSize: CanvasSize,
  viewportSize: ViewportSize,
  padding: number = 40
): ZoomPanState {
  const availableWidth = viewportSize.width - padding * 2;
  const availableHeight = viewportSize.height - padding * 2;

  if (availableWidth <= 0 || availableHeight <= 0) {
    return INITIAL_ZOOM_PAN_STATE;
  }

  const scaleX = availableWidth / canvasSize.width;
  const scaleY = availableHeight / canvasSize.height;
  const zoom = Math.min(scaleX, scaleY);

  // Center the canvas in the viewport
  const panX = (viewportSize.width - canvasSize.width * zoom) / 2;
  const panY = (viewportSize.height - canvasSize.height * zoom) / 2;

  return { zoom, panX, panY };
}

/**
 * Calculate fill-to-screen zoom level.
 * Finds the zoom that fills the viewport (may crop the canvas).
 */
export function calculateFillToScreen(
  canvasSize: CanvasSize,
  viewportSize: ViewportSize
): ZoomPanState {
  const scaleX = viewportSize.width / canvasSize.width;
  const scaleY = viewportSize.height / canvasSize.height;
  const zoom = Math.max(scaleX, scaleY);

  const panX = (viewportSize.width - canvasSize.width * zoom) / 2;
  const panY = (viewportSize.height - canvasSize.height * zoom) / 2;

  return { zoom, panX, panY };
}

/**
 * Reset zoom and pan to initial state (100%, centered).
 */
export function resetZoomPan(): ZoomPanState {
  return { ...INITIAL_ZOOM_PAN_STATE };
}

/**
 * Set zoom to a specific preset level, centering the canvas.
 */
export function setZoomToPreset(
  preset: number,
  canvasSize: CanvasSize,
  viewportSize: ViewportSize,
  config: ZoomPanConfig = DEFAULT_ZOOM_PAN_CONFIG
): ZoomPanState {
  const zoom = clampZoom(preset, config);
  const panX = (viewportSize.width - canvasSize.width * zoom) / 2;
  const panY = (viewportSize.height - canvasSize.height * zoom) / 2;
  return { zoom, panX, panY };
}

// ============================================================================
// PAN FUNCTIONS
// ============================================================================

/**
 * Apply pan delta to current state.
 */
export function applyPanDelta(
  state: ZoomPanState,
  deltaX: number,
  deltaY: number
): ZoomPanState {
  return {
    ...state,
    panX: state.panX + deltaX,
    panY: state.panY + deltaY,
  };
}

/**
 * Set pan to absolute position.
 */
export function setPanPosition(
  state: ZoomPanState,
  panX: number,
  panY: number
): ZoomPanState {
  return { ...state, panX, panY };
}

/**
 * Center canvas in viewport at current zoom level.
 */
export function centerCanvas(
  state: ZoomPanState,
  canvasSize: CanvasSize,
  viewportSize: ViewportSize
): ZoomPanState {
  const panX = (viewportSize.width - canvasSize.width * state.zoom) / 2;
  const panY = (viewportSize.height - canvasSize.height * state.zoom) / 2;
  return { ...state, panX, panY };
}

// ============================================================================
// COORDINATE CONVERSION
// ============================================================================

/**
 * Convert viewport (screen) coordinates to canvas coordinates.
 */
export function viewportToCanvas(
  viewportPoint: Point2D,
  state: ZoomPanState
): Point2D {
  return {
    x: (viewportPoint.x - state.panX) / state.zoom,
    y: (viewportPoint.y - state.panY) / state.zoom,
  };
}

/**
 * Convert canvas coordinates to viewport (screen) coordinates.
 */
export function canvasToViewport(
  canvasPoint: Point2D,
  state: ZoomPanState
): Point2D {
  return {
    x: canvasPoint.x * state.zoom + state.panX,
    y: canvasPoint.y * state.zoom + state.panY,
  };
}

// ============================================================================
// UTILITY
// ============================================================================

/**
 * Format zoom level as percentage string (e.g., "100%", "150%").
 */
export function formatZoomPercent(zoom: number): string {
  return `${Math.round(zoom * 100)}%`;
}

/**
 * Find the nearest preset zoom level.
 */
export function getNearestPreset(zoom: number): number {
  let nearest: number = ZOOM_PRESETS[0];
  let minDiff = Math.abs(zoom - nearest);

  for (const preset of ZOOM_PRESETS) {
    const diff = Math.abs(zoom - preset);
    if (diff < minDiff) {
      minDiff = diff;
      nearest = preset;
    }
  }

  return nearest;
}

/**
 * Check if a keyboard event matches a zoom shortcut.
 */
export function isZoomShortcut(event: KeyboardEvent): 'in' | 'out' | 'fit' | 'reset' | null {
  const isCtrlCmd = event.ctrlKey || event.metaKey;
  if (!isCtrlCmd) return null;

  switch (event.key) {
    case '=':
    case '+':
      return 'in';
    case '-':
    case '_':
      return 'out';
    case '0':
      return 'fit';
    case '1':
      return 'reset';
    default:
      return null;
  }
}
